-- ================================================================
-- ShopKietZ – Full Database Dump (Schema + Data)
-- Idempotent. Run on a fresh Supabase project via SQL Editor.
-- ================================================================
SET client_min_messages = warning;
SET session_replication_role = replica;

-- ---------- Extensions ----------
CREATE EXTENSION IF NOT EXISTS "pgcrypto";
CREATE EXTENSION IF NOT EXISTS "uuid-ossp";

-- ---------- Enum ----------
DO $$ BEGIN
  CREATE TYPE public.app_role AS ENUM ('admin','user','ctv');
EXCEPTION WHEN duplicate_object THEN NULL; END $$;

-- ================================================================
-- TABLES
-- ================================================================

CREATE TABLE IF NOT EXISTS public.profiles (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id uuid NOT NULL UNIQUE,
  username text,
  display_name text,
  avatar_url text,
  balance integer NOT NULL DEFAULT 0,
  transfer_code text UNIQUE,
  bio text,
  phone text,
  created_at timestamptz NOT NULL DEFAULT now(),
  updated_at timestamptz NOT NULL DEFAULT now()
);

CREATE TABLE IF NOT EXISTS public.user_roles (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id uuid NOT NULL,
  role public.app_role NOT NULL,
  UNIQUE (user_id, role)
);

CREATE TABLE IF NOT EXISTS public.categories (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  name text NOT NULL,
  slug text NOT NULL UNIQUE,
  image_url text,
  sort_order integer DEFAULT 0,
  created_at timestamptz NOT NULL DEFAULT now()
);

CREATE TABLE IF NOT EXISTS public.products (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  name text NOT NULL,
  description text,
  price integer NOT NULL,
  stock integer NOT NULL DEFAULT 0,
  category text NOT NULL,
  image_url text,
  status text NOT NULL DEFAULT 'active',
  product_type text DEFAULT 'account',
  account_info text,
  created_at timestamptz NOT NULL DEFAULT now(),
  updated_at timestamptz NOT NULL DEFAULT now()
);

CREATE TABLE IF NOT EXISTS public.product_accounts (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  product_id uuid NOT NULL REFERENCES public.products(id) ON DELETE CASCADE,
  account_info text NOT NULL,
  is_sold boolean NOT NULL DEFAULT false,
  sold_to_order_id uuid,
  created_at timestamptz NOT NULL DEFAULT now()
);

CREATE TABLE IF NOT EXISTS public.orders (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id uuid NOT NULL,
  product_name text NOT NULL,
  product_category text NOT NULL,
  price integer NOT NULL,
  account_info text,
  order_code text,
  status text NOT NULL DEFAULT 'success',
  created_at timestamptz NOT NULL DEFAULT now()
);

CREATE TABLE IF NOT EXISTS public.boost_orders (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id uuid NOT NULL,
  product_id uuid NOT NULL,
  product_name text NOT NULL,
  price integer NOT NULL,
  account_username text NOT NULL,
  account_password text NOT NULL,
  customer_note text,
  admin_note text,
  status text NOT NULL DEFAULT 'pending',
  refunded boolean NOT NULL DEFAULT false,
  order_code text,
  created_at timestamptz NOT NULL DEFAULT now(),
  updated_at timestamptz NOT NULL DEFAULT now()
);

CREATE TABLE IF NOT EXISTS public.topup_requests (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id uuid NOT NULL,
  amount integer NOT NULL,
  method text,
  status text NOT NULL DEFAULT 'pending',
  transfer_code text,
  request_id text,
  card_result text,
  note text,
  created_at timestamptz NOT NULL DEFAULT now(),
  updated_at timestamptz NOT NULL DEFAULT now()
);

CREATE TABLE IF NOT EXISTS public.discount_codes (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  code text NOT NULL UNIQUE,
  discount_percent integer NOT NULL DEFAULT 0,
  discount_amount integer NOT NULL DEFAULT 0,
  max_uses integer,
  used_count integer NOT NULL DEFAULT 0,
  min_order_amount integer NOT NULL DEFAULT 0,
  is_active boolean NOT NULL DEFAULT true,
  expires_at timestamptz,
  created_at timestamptz NOT NULL DEFAULT now()
);

CREATE TABLE IF NOT EXISTS public.ctv_assignments (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  email text NOT NULL,
  user_id uuid,
  assigned_categories text[] NOT NULL DEFAULT '{}',
  is_active boolean NOT NULL DEFAULT true,
  created_at timestamptz NOT NULL DEFAULT now()
);

CREATE TABLE IF NOT EXISTS public.shop_settings (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  key text NOT NULL UNIQUE,
  value text,
  updated_at timestamptz NOT NULL DEFAULT now()
);

-- ================================================================
-- GRANTS
-- ================================================================
GRANT SELECT, INSERT, UPDATE, DELETE ON public.profiles TO authenticated;
GRANT SELECT ON public.profiles TO anon;
GRANT ALL ON public.profiles TO service_role;

GRANT SELECT ON public.user_roles TO authenticated;
GRANT ALL ON public.user_roles TO service_role;

GRANT SELECT ON public.categories TO anon, authenticated;
GRANT ALL ON public.categories TO service_role;

GRANT SELECT ON public.products TO anon, authenticated;
GRANT ALL ON public.products TO service_role;

GRANT SELECT, INSERT, UPDATE, DELETE ON public.product_accounts TO authenticated;
GRANT ALL ON public.product_accounts TO service_role;

GRANT SELECT, INSERT, UPDATE, DELETE ON public.orders TO authenticated;
GRANT ALL ON public.orders TO service_role;

GRANT SELECT, INSERT, UPDATE, DELETE ON public.boost_orders TO authenticated;
GRANT ALL ON public.boost_orders TO service_role;

GRANT SELECT, INSERT, UPDATE, DELETE ON public.topup_requests TO authenticated;
GRANT ALL ON public.topup_requests TO service_role;

GRANT SELECT ON public.discount_codes TO anon, authenticated;
GRANT ALL ON public.discount_codes TO service_role;

GRANT SELECT ON public.ctv_assignments TO authenticated;
GRANT ALL ON public.ctv_assignments TO service_role;

GRANT SELECT ON public.shop_settings TO anon, authenticated;
GRANT ALL ON public.shop_settings TO service_role;

-- ================================================================
-- FUNCTIONS
-- ================================================================
CREATE OR REPLACE FUNCTION public.assign_transfer_code()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF NEW.transfer_code IS NULL THEN
    NEW.transfer_code := generate_transfer_code();
  END IF;
  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.cancel_boost_order(p_order_id uuid, p_refund boolean, p_admin_note text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE v_order boost_orders%ROWTYPE; BEGIN
  IF NOT public.has_role(auth.uid(), 'admin'::app_role) THEN
    RETURN jsonb_build_object('success', false, 'error', 'Forbidden');
  END IF;
  SELECT * INTO v_order FROM boost_orders WHERE id = p_order_id FOR UPDATE;
  IF NOT FOUND THEN RETURN jsonb_build_object('success', false, 'error', 'Order not found'); END IF;
  IF v_order.status IN ('completed','cancelled','cancelled_refunded') THEN
    RETURN jsonb_build_object('success', false, 'error', 'Đơn đã đóng');
  END IF;
  IF p_refund THEN
    UPDATE profiles SET balance = balance + v_order.price WHERE user_id = v_order.user_id;
    UPDATE boost_orders SET status='cancelled_refunded', refunded=true, admin_note=p_admin_note WHERE id=p_order_id;
  ELSE
    UPDATE boost_orders SET status='cancelled', admin_note=p_admin_note WHERE id=p_order_id;
  END IF;
  RETURN jsonb_build_object('success', true);
END; $function$
;

CREATE OR REPLACE FUNCTION public.generate_transfer_code()
 RETURNS text
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
DECLARE
  new_code text;
  code_exists boolean;
BEGIN
  LOOP
    new_code := 'VAK' || lpad(floor(random() * 1000)::text, 3, '0');
    SELECT EXISTS(SELECT 1 FROM profiles WHERE transfer_code = new_code) INTO code_exists;
    IF NOT code_exists THEN
      RETURN new_code;
    END IF;
  END LOOP;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_email_by_username(p_username text)
 RETURNS text
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT u.email
  FROM public.profiles p
  JOIN auth.users u ON u.id = p.user_id
  WHERE lower(p.username) = lower(p_username)
  LIMIT 1;
$function$
;

CREATE OR REPLACE FUNCTION public.get_recent_purchases(limit_count integer DEFAULT 10)
 RETURNS TABLE(product_name text, product_category text, price integer, created_at timestamp with time zone, display_name text, avatar_url text)
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT o.product_name, o.product_category, o.price, o.created_at, p.display_name, p.avatar_url
  FROM orders o
  JOIN profiles p ON p.user_id = o.user_id
  ORDER BY o.created_at DESC
  LIMIT limit_count;
$function$
;

CREATE OR REPLACE FUNCTION public.get_topup_leaderboard(limit_count integer DEFAULT 10)
 RETURNS TABLE(user_id uuid, display_name text, avatar_url text, total_amount bigint)
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT t.user_id, p.display_name, p.avatar_url, sum(t.amount)::bigint as total_amount
  FROM topup_requests t
  JOIN profiles p ON p.user_id = t.user_id
  WHERE t.status = 'approved'
  GROUP BY t.user_id, p.display_name, p.avatar_url
  ORDER BY total_amount DESC
  LIMIT limit_count;
$function$
;

CREATE OR REPLACE FUNCTION public.handle_new_user()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  VALUES (
    NEW.id,
    COALESCE(NEW.raw_user_meta_data->>'full_name', NEW.raw_user_meta_data->>'username', NEW.email),
    NEW.raw_user_meta_data->>'username'
  );
  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.has_role(_user_id uuid, _role app_role)
 RETURNS boolean
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT EXISTS (
    SELECT 1 FROM public.user_roles
    WHERE user_id = _user_id AND role = _role
  )
$function$
;

CREATE OR REPLACE FUNCTION public.is_active_ctv(_user_id uuid)
 RETURNS boolean
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT EXISTS (
    SELECT 1 FROM public.ctv_assignments
    WHERE lower(email) = lower((SELECT email FROM auth.users WHERE id = _user_id))
      AND is_active = true
  )
$function$
;

CREATE OR REPLACE FUNCTION public.is_ctv_for_category(_user_id uuid, _category text)
 RETURNS boolean
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT EXISTS (
    SELECT 1 FROM public.ctv_assignments
    WHERE lower(email) = lower((SELECT email FROM auth.users WHERE id = _user_id))
      AND is_active = true
      AND _category = ANY(assigned_categories)
  )
$function$
;

CREATE OR REPLACE FUNCTION public.purchase_boost(p_user_id uuid, p_product_id uuid, p_username text, p_password text, p_note text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_product products%ROWTYPE;
  v_profile profiles%ROWTYPE;
  v_order_id uuid;
  v_order_code text := 'VAK';
  v_chars text := 'ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789';
  v_i int;
BEGIN
  IF p_user_id IS NULL OR p_user_id <> auth.uid() THEN
    RETURN jsonb_build_object('success', false, 'error', 'Không hợp lệ');
  END IF;
  IF coalesce(trim(p_username),'') = '' OR coalesce(trim(p_password),'') = '' THEN
    RETURN jsonb_build_object('success', false, 'error', 'Vui lòng nhập tài khoản và mật khẩu');
  END IF;
  SELECT * INTO v_product FROM products WHERE id = p_product_id AND status = 'active' AND product_type = 'boost';
  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'Dịch vụ cày thuê không tồn tại');
  END IF;
  SELECT * INTO v_profile FROM profiles WHERE user_id = p_user_id FOR UPDATE;
  IF NOT FOUND OR v_profile.balance < v_product.price THEN
    RETURN jsonb_build_object('success', false, 'error', 'Số dư không đủ');
  END IF;

  FOR v_i IN 1..12 LOOP
    v_order_code := v_order_code || substr(v_chars, floor(random()*36+1)::int, 1);
  END LOOP;

    VALUES (p_user_id, v_product.id, v_product.name, v_product.price, p_username, p_password, p_note, v_order_code)
    RETURNING id INTO v_order_id;

  UPDATE profiles SET balance = balance - v_product.price WHERE user_id = p_user_id;

  RETURN jsonb_build_object('success', true, 'order_code', v_order_code, 'order_id', v_order_id);
END; $function$
;

CREATE OR REPLACE FUNCTION public.purchase_product(p_user_id uuid, p_product_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_product products%ROWTYPE;
  v_account product_accounts%ROWTYPE;
  v_profile profiles%ROWTYPE;
  v_order_code text;
  v_order_id uuid;
  v_chars text := 'ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789';
  v_i integer;
BEGIN
  SELECT * INTO v_product FROM products WHERE id = p_product_id AND status = 'active';
  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'Sản phẩm không tồn tại');
  END IF;

  SELECT * INTO v_account FROM product_accounts
    WHERE product_id = p_product_id AND is_sold = false
    LIMIT 1 FOR UPDATE SKIP LOCKED;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'Hết hàng');
  END IF;

  SELECT * INTO v_profile FROM profiles WHERE user_id = p_user_id FOR UPDATE;
  IF NOT FOUND OR v_profile.balance < v_product.price THEN
    RETURN jsonb_build_object('success', false, 'error', 'Số dư không đủ');
  END IF;

  v_order_code := 'VAK';
  FOR v_i IN 1..12 LOOP
    v_order_code := v_order_code || substr(v_chars, floor(random() * 36 + 1)::int, 1);
  END LOOP;

    VALUES (p_user_id, v_product.name, v_product.category, v_product.price, v_account.account_info, v_order_code)
    RETURNING id INTO v_order_id;

  UPDATE product_accounts SET is_sold = true, sold_to_order_id = v_order_id WHERE id = v_account.id;
  UPDATE products SET stock = (SELECT count(*) FROM product_accounts WHERE product_id = p_product_id AND is_sold = false) WHERE id = p_product_id;
  UPDATE profiles SET balance = balance - v_product.price WHERE user_id = p_user_id;

  RETURN jsonb_build_object('success', true, 'order_code', v_order_code, 'order_id', v_order_id, 'account_info', v_account.account_info);
END;
$function$
;

CREATE OR REPLACE FUNCTION public.purchase_product_batch(p_user_id uuid, p_product_id uuid, p_quantity integer, p_discount_code text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_product products%ROWTYPE;
  v_profile profiles%ROWTYPE;
  v_order_code text;
  v_order_id uuid;
  v_chars text := 'ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789';
  v_i integer;
  v_total_price integer;
  v_discount_amount integer := 0;
  v_final_price integer;
  v_account_infos text[];
  v_account record;
  v_count integer := 0;
  v_discount discount_codes%ROWTYPE;
BEGIN
  IF p_quantity < 1 OR p_quantity > 100 THEN
    RETURN jsonb_build_object('success', false, 'error', 'Số lượng không hợp lệ');
  END IF;

  SELECT * INTO v_product FROM products WHERE id = p_product_id AND status = 'active';
  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'Sản phẩm không tồn tại');
  END IF;

  v_total_price := v_product.price * p_quantity;

  IF p_discount_code IS NOT NULL AND p_discount_code != '' THEN
    SELECT * INTO v_discount FROM discount_codes
      WHERE code = upper(p_discount_code) AND is_active = true;
    
    IF FOUND THEN
      IF v_discount.max_uses IS NOT NULL AND v_discount.used_count >= v_discount.max_uses THEN
        RETURN jsonb_build_object('success', false, 'error', 'Mã giảm giá đã hết lượt sử dụng');
      END IF;
      IF v_discount.expires_at IS NOT NULL AND v_discount.expires_at < now() THEN
        RETURN jsonb_build_object('success', false, 'error', 'Mã giảm giá đã hết hạn');
      END IF;
      IF v_discount.min_order_amount > 0 AND v_total_price < v_discount.min_order_amount THEN
        RETURN jsonb_build_object('success', false, 'error', 'Đơn tối thiểu ' || v_discount.min_order_amount || 'đ');
      END IF;

      IF v_discount.discount_percent > 0 THEN
        v_discount_amount := v_discount_amount + floor(v_total_price * v_discount.discount_percent / 100);
      END IF;
      IF v_discount.discount_amount > 0 THEN
        v_discount_amount := v_discount_amount + v_discount.discount_amount;
      END IF;
    ELSE
      RETURN jsonb_build_object('success', false, 'error', 'Mã giảm giá không hợp lệ');
    END IF;
  END IF;

  v_final_price := GREATEST(0, v_total_price - v_discount_amount);

  SELECT * INTO v_profile FROM profiles WHERE user_id = p_user_id FOR UPDATE;
  IF NOT FOUND OR v_profile.balance < v_final_price THEN
    RETURN jsonb_build_object('success', false, 'error', 'Số dư không đủ. Cần ' || v_final_price || 'đ');
  END IF;

  v_account_infos := ARRAY[]::text[];
  FOR v_account IN
    SELECT * FROM product_accounts
    WHERE product_id = p_product_id AND is_sold = false
    ORDER BY created_at
    LIMIT p_quantity
    FOR UPDATE SKIP LOCKED
  LOOP
    v_account_infos := array_append(v_account_infos, v_account.account_info);
    v_count := v_count + 1;
  END LOOP;

  IF v_count < p_quantity THEN
    RETURN jsonb_build_object('success', false, 'error', 'Không đủ hàng. Chỉ còn ' || v_count || ' sản phẩm');
  END IF;

  v_order_code := 'VAK';
  FOR v_i IN 1..12 LOOP
    v_order_code := v_order_code || substr(v_chars, floor(random() * 36 + 1)::int, 1);
  END LOOP;

    VALUES (p_user_id, v_product.name, v_product.category, v_final_price, array_to_string(v_account_infos, E'\n'), v_order_code)
    RETURNING id INTO v_order_id;

  UPDATE product_accounts SET is_sold = true, sold_to_order_id = v_order_id
    WHERE product_id = p_product_id AND is_sold = false
    AND id IN (
      SELECT id FROM product_accounts
      WHERE product_id = p_product_id AND is_sold = false
      ORDER BY created_at
      LIMIT p_quantity
    );

  UPDATE products SET stock = (SELECT count(*) FROM product_accounts WHERE product_id = p_product_id AND is_sold = false) WHERE id = p_product_id;
  UPDATE profiles SET balance = balance - v_final_price WHERE user_id = p_user_id;

  IF p_discount_code IS NOT NULL AND p_discount_code != '' AND v_discount.id IS NOT NULL THEN
    UPDATE discount_codes SET used_count = used_count + 1 WHERE id = v_discount.id;
  END IF;

  RETURN jsonb_build_object(
    'success', true,
    'order_code', v_order_code,
    'order_id', v_order_id,
    'account_infos', to_jsonb(v_account_infos),
    'total_price', v_final_price,
    'discount_amount', v_discount_amount,
    'quantity', p_quantity
  );
END;
$function$
;

CREATE OR REPLACE FUNCTION public.update_updated_at_column()
 RETURNS trigger
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
BEGIN
  NEW.updated_at = now();
  RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.username_available(p_username text)
 RETURNS boolean
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT NOT EXISTS (SELECT 1 FROM public.profiles WHERE lower(username) = lower(p_username));
$function$
;


-- ================================================================
-- TRIGGERS
-- ================================================================
DROP TRIGGER IF EXISTS on_auth_user_created ON auth.users;
CREATE TRIGGER on_auth_user_created
  AFTER INSERT ON auth.users
  FOR EACH ROW EXECUTE FUNCTION public.handle_new_user();

DROP TRIGGER IF EXISTS assign_transfer_code_trigger ON public.profiles;
CREATE TRIGGER assign_transfer_code_trigger
  BEFORE INSERT ON public.profiles
  FOR EACH ROW EXECUTE FUNCTION public.assign_transfer_code();

DROP TRIGGER IF EXISTS update_profiles_updated_at ON public.profiles;
CREATE TRIGGER update_profiles_updated_at
  BEFORE UPDATE ON public.profiles
  FOR EACH ROW EXECUTE FUNCTION public.update_updated_at_column();

DROP TRIGGER IF EXISTS update_products_updated_at ON public.products;
CREATE TRIGGER update_products_updated_at
  BEFORE UPDATE ON public.products
  FOR EACH ROW EXECUTE FUNCTION public.update_updated_at_column();

DROP TRIGGER IF EXISTS update_boost_orders_updated_at ON public.boost_orders;
CREATE TRIGGER update_boost_orders_updated_at
  BEFORE UPDATE ON public.boost_orders
  FOR EACH ROW EXECUTE FUNCTION public.update_updated_at_column();

DROP TRIGGER IF EXISTS update_topup_requests_updated_at ON public.topup_requests;
CREATE TRIGGER update_topup_requests_updated_at
  BEFORE UPDATE ON public.topup_requests
  FOR EACH ROW EXECUTE FUNCTION public.update_updated_at_column();

DROP TRIGGER IF EXISTS update_shop_settings_updated_at ON public.shop_settings;
CREATE TRIGGER update_shop_settings_updated_at
  BEFORE UPDATE ON public.shop_settings
  FOR EACH ROW EXECUTE FUNCTION public.update_updated_at_column();

-- ================================================================
-- INDEXES
-- ================================================================
CREATE INDEX IF NOT EXISTS idx_profiles_user_id ON public.profiles(user_id);
CREATE INDEX IF NOT EXISTS idx_user_roles_user_id ON public.user_roles(user_id);
CREATE INDEX IF NOT EXISTS idx_products_category ON public.products(category);
CREATE INDEX IF NOT EXISTS idx_products_status ON public.products(status);
CREATE INDEX IF NOT EXISTS idx_product_accounts_product_id ON public.product_accounts(product_id);
CREATE INDEX IF NOT EXISTS idx_product_accounts_is_sold ON public.product_accounts(is_sold);
CREATE INDEX IF NOT EXISTS idx_orders_user_id ON public.orders(user_id);
CREATE INDEX IF NOT EXISTS idx_orders_created_at ON public.orders(created_at DESC);
CREATE INDEX IF NOT EXISTS idx_boost_orders_user_id ON public.boost_orders(user_id);
CREATE INDEX IF NOT EXISTS idx_boost_orders_status ON public.boost_orders(status);
CREATE INDEX IF NOT EXISTS idx_topup_requests_user_id ON public.topup_requests(user_id);
CREATE INDEX IF NOT EXISTS idx_topup_requests_status ON public.topup_requests(status);
CREATE INDEX IF NOT EXISTS idx_shop_settings_key ON public.shop_settings(key);

-- ================================================================
-- ROW LEVEL SECURITY
-- ================================================================
ALTER TABLE public.profiles ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.user_roles ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.categories ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.products ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.product_accounts ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.orders ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.boost_orders ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.topup_requests ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.discount_codes ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.ctv_assignments ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.shop_settings ENABLE ROW LEVEL SECURITY;

-- ---- profiles ----
DROP POLICY IF EXISTS "Public profiles are viewable" ON public.profiles;
CREATE POLICY "Public profiles are viewable" ON public.profiles FOR SELECT USING (true);
DROP POLICY IF EXISTS "Users can update own profile" ON public.profiles;
CREATE POLICY "Users can update own profile" ON public.profiles FOR UPDATE USING (auth.uid() = user_id);
DROP POLICY IF EXISTS "Users can insert own profile" ON public.profiles;
CREATE POLICY "Users can insert own profile" ON public.profiles FOR INSERT WITH CHECK (auth.uid() = user_id);
DROP POLICY IF EXISTS "Admins manage profiles" ON public.profiles;
CREATE POLICY "Admins manage profiles" ON public.profiles FOR ALL USING (public.has_role(auth.uid(),'admin'));

-- ---- user_roles ----
DROP POLICY IF EXISTS "Users see own roles" ON public.user_roles;
CREATE POLICY "Users see own roles" ON public.user_roles FOR SELECT USING (auth.uid() = user_id);
DROP POLICY IF EXISTS "Admins manage roles" ON public.user_roles;
CREATE POLICY "Admins manage roles" ON public.user_roles FOR ALL USING (public.has_role(auth.uid(),'admin'));

-- ---- categories ----
DROP POLICY IF EXISTS "Anyone can view categories" ON public.categories;
CREATE POLICY "Anyone can view categories" ON public.categories FOR SELECT USING (true);
DROP POLICY IF EXISTS "Admins manage categories" ON public.categories;
CREATE POLICY "Admins manage categories" ON public.categories FOR ALL USING (public.has_role(auth.uid(),'admin'));

-- ---- products ----
DROP POLICY IF EXISTS "Anyone can view products" ON public.products;
CREATE POLICY "Anyone can view products" ON public.products FOR SELECT USING (true);
DROP POLICY IF EXISTS "Admins manage products" ON public.products;
CREATE POLICY "Admins manage products" ON public.products FOR ALL USING (public.has_role(auth.uid(),'admin'));
DROP POLICY IF EXISTS "CTV manage own category products" ON public.products;
CREATE POLICY "CTV manage own category products" ON public.products FOR ALL
  USING (public.is_ctv_for_category(auth.uid(), category));

-- ---- product_accounts ----
DROP POLICY IF EXISTS "Admins manage product accounts" ON public.product_accounts;
CREATE POLICY "Admins manage product accounts" ON public.product_accounts FOR ALL USING (public.has_role(auth.uid(),'admin'));

-- ---- orders ----
DROP POLICY IF EXISTS "Users see own orders" ON public.orders;
CREATE POLICY "Users see own orders" ON public.orders FOR SELECT USING (auth.uid() = user_id);
DROP POLICY IF EXISTS "Admins manage orders" ON public.orders;
CREATE POLICY "Admins manage orders" ON public.orders FOR ALL USING (public.has_role(auth.uid(),'admin'));

-- ---- boost_orders ----
DROP POLICY IF EXISTS "Users see own boost orders" ON public.boost_orders;
CREATE POLICY "Users see own boost orders" ON public.boost_orders FOR SELECT USING (auth.uid() = user_id);
DROP POLICY IF EXISTS "Users create own boost orders" ON public.boost_orders;
CREATE POLICY "Users create own boost orders" ON public.boost_orders FOR INSERT WITH CHECK (auth.uid() = user_id);
DROP POLICY IF EXISTS "Admins manage boost orders" ON public.boost_orders;
CREATE POLICY "Admins manage boost orders" ON public.boost_orders FOR ALL USING (public.has_role(auth.uid(),'admin'));

-- ---- topup_requests ----
DROP POLICY IF EXISTS "Users see own topups" ON public.topup_requests;
CREATE POLICY "Users see own topups" ON public.topup_requests FOR SELECT USING (auth.uid() = user_id);
DROP POLICY IF EXISTS "Users create own topups" ON public.topup_requests;
CREATE POLICY "Users create own topups" ON public.topup_requests FOR INSERT WITH CHECK (auth.uid() = user_id);
DROP POLICY IF EXISTS "Admins manage topups" ON public.topup_requests;
CREATE POLICY "Admins manage topups" ON public.topup_requests FOR ALL USING (public.has_role(auth.uid(),'admin'));

-- ---- discount_codes ----
DROP POLICY IF EXISTS "Anyone can view active codes" ON public.discount_codes;
CREATE POLICY "Anyone can view active codes" ON public.discount_codes FOR SELECT USING (is_active = true);
DROP POLICY IF EXISTS "Admins manage discount codes" ON public.discount_codes;
CREATE POLICY "Admins manage discount codes" ON public.discount_codes FOR ALL USING (public.has_role(auth.uid(),'admin'));

-- ---- ctv_assignments ----
DROP POLICY IF EXISTS "CTV see own assignment" ON public.ctv_assignments;
CREATE POLICY "CTV see own assignment" ON public.ctv_assignments FOR SELECT
  USING (lower(email) = lower((SELECT email FROM auth.users WHERE id = auth.uid())));
DROP POLICY IF EXISTS "Admins manage ctv assignments" ON public.ctv_assignments;
CREATE POLICY "Admins manage ctv assignments" ON public.ctv_assignments FOR ALL USING (public.has_role(auth.uid(),'admin'));

-- ---- shop_settings ----
DROP POLICY IF EXISTS "Public can view non-sensitive shop settings" ON public.shop_settings;
CREATE POLICY "Public can view non-sensitive shop settings" ON public.shop_settings FOR SELECT
  USING (key NOT IN ('charge_card_api'));
DROP POLICY IF EXISTS "Admins manage shop settings" ON public.shop_settings;
CREATE POLICY "Admins manage shop settings" ON public.shop_settings FOR ALL USING (public.has_role(auth.uid(),'admin'));

